class Greeter:
    def __enter__(self):
        print("Opening")
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        print("Closing")
        return False

with Greeter():
    print("Inside")

from contextlib import contextmanager

@contextmanager
def open_resource():
    print("Setup")
    yield
    print("Cleanup")  # May be skipped on error!

